SELECT id, order_no, country_name, has_area_code, scheduled_time, status, CASE status WHEN 0 THEN '待发送' WHEN 1 THEN '发送中' WHEN 2 THEN '已完成' WHEN 3 THEN '发送失败' WHEN 4 THEN '已取消' ELSE '未知' END AS status_desc, success_count, fail_count, total_count, create_time FROM sms_order
AND order_no LIKE CONCAT('%', #{queryParams.orderNo}, '%')
AND country_id = #{queryParams.countryId}
AND status = #{queryParams.status}
AND create_by = #{currentUserId}
ORDER BY create_time DESC

SELECT id, create_by AS userId, total_count AS totalCount, success_count AS successCount, report_count AS reportCount, paid_count AS paidCount, fail_count AS failCount, cancel_count AS cancelCount, create_time, update_time, status, CASE status WHEN 0 THEN '待发送' WHEN 1 THEN '发送中' WHEN 2 THEN '已完成' WHEN 3 THEN '发送失败' WHEN 4 THEN '已取消' ELSE '未知' END AS statusDesc FROM sms_order
AND id = #{queryParams.orderId}
AND country_id = #{queryParams.countryId}
AND create_time >= #{queryParams.startTime}
AND create_time <= #{queryParams.endTime}
AND create_by = #{currentUserId}
ORDER BY create_time DESC
